import React from 'react';

const QuantumMetadataPanel = ({ details }) => {
    if (!details) {
        return <p>No quantum details available.</p>;
    }
    return (
        <div>
            <h2>Quantum Metadata Panel</h2>
            <p>Details: {details}</p>
        </div>
    );
};

export default QuantumMetadataPanel;
